import React from 'react';

const entries = [
  {
    degree: 'Bachelor of Science in Information Technology',
    major: 'Major in Web Technology',
    school: 'Your University Name',
    year: '2023 – Present',
  },
  {
    degree: 'Senior High School',
    major: 'STEM / ICT Track',
    school: 'Your Senior High School',
    year: '2021 – 2023',
  },
];

const Education = () => (
  <section
    id="Education"
    className="min-h-screen flex flex-col justify-center items-center px-5 py-24"
    style={{ background: '#0d1117' }}
  >
    <h1 className="font-bold text-4xl text-white text-center mb-10">Education</h1>
    <div className="w-full max-w-2xl flex flex-col gap-5">
      {entries.map((e, i) => (
        <div
          key={i}
          className="rounded-xl p-6 transition-transform duration-300 hover:-translate-y-1"
          style={{ background: 'rgba(255,255,255,0.05)', border: '1px solid rgba(255,255,255,0.1)' }}
        >
          <h3 className="font-bold text-base" style={{ color: '#004097' }}>{e.degree}</h3>
          <p className="italic text-sm text-gray-400 mt-1">{e.major}</p>
          <p className="text-white mt-2 text-sm">{e.school}</p>
          <p className="text-gray-500 text-xs mt-1">{e.year}</p>
        </div>
      ))}
    </div>
  </section>
);

export default Education;
